import java.io.IOException;

public class SecureCommandInjectionExample {

    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "ls";

        // Sanitize and validate user input (in this example, we assume it's already sanitized)

        // Build the command with proper separation of command and arguments using ProcessBuilder
        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command("ls", userInput);

        // Start the process
        Process process = processBuilder.start();

        // Reading the output of the command
        java.util.Scanner scanner = new java.util.Scanner(process.getInputStream());
        while (scanner.hasNextLine()) {
            System.out.println(scanner.nextLine());
        }
    }
}

